arguments.command:
$start = Get-Date
$timeout = 300 # 5分钟等待Unity启动
while ((Get-Date) -lt $start.AddSeconds($timeout)) {
    $unity = Get-Process -Name "Unity" -ErrorAction SilentlyContinue | Where-Object { $_.CommandLine -like "*RunHotUpdatePipeline*" -or $_.StartTime -gt $start.AddSeconds(-10) }
    if ($unity) {
        Write-Host "Unity进程已启动: PID=$($unity.Id), StartTime=$($unity.StartTime)"
        break
    }
    $logFile = Get-Item "E:\Solo\nightoffullmoon\client\cardv\BuildPipeline_RunHotUpdate.log" -ErrorAction SilentlyContinue
    if ($logFile -and $logFile.LastWriteTime -gt $start) {
        Write-Host "日志已更新: $($logFile.LastWriteTime)"
        break
    }
    Start-Sleep -Seconds 5
    Write-Host "等待Unity启动... $(Get-Date -Format 'HH:mm:ss')"
}
Write-Host "检查结束"

$content = Get-Content "E:\Solo\nightoffullmoon\client\cardv\BuildPipeline_RunHotUpdate.log"
$lines = $content | Select-String -Pattern "RunHotUpdate|BuildPipeline|HotUpdate|Pipeline|热更|upload|CDN|bundle|Bundle|成功|完成|finish|complete|error|Error|fail|Fail|step|Step" -CaseSensitive:$false
$lines | Select-Object -Last 30 | ForEach-Object { Write-Host $_.Line }

$before = (Get-Item "E:\Solo\nightoffullmoon\client\cardv\BuildPipeline_RunHotUpdate.log").LastWriteTime
Write-Host "Log before: $before"
Write-Host "Running bat..."
$result = Start-Process -FilePath "E:\Solo\nightoffullmoon\client\cardv\RunBuildPipelineHotUpdate.bat" -Wait -PassThru -NoNewWindow
Write-Host "Bat exit code: $($result.ExitCode)"
$after = (Get-Item "E:\Solo\nightoffullmoon\client\cardv\BuildPipeline_RunHotUpdate.log").LastWriteTime
Write-Host "Log after: $after"
if ($after -gt $before) {
    Write-Host "Log was updated!"
    Get-Content "E:\Solo\nightoffullmoon\client\cardv\BuildPipeline_RunHotUpdate.log" -Tail 10
} else {
    Write-Host "Log was NOT updated - Unity may have failed to start"
}

$logFile = "E:\Solo\nightoffullmoon\client\cardv\BuildPipeline_RunHotUpdate.log"
# 找流水线最终状态
Get-Content $logFile | Select-String -Pattern "Pipeline|pipeline|热更|success|fail|jump out|Jump out|Succeeded|Failed|All done|Completed" -CaseSensitive:$false | Select-Object -Last 20 | ForEach-Object { Write-Host $_.Line }
